package com.enterprise.auth.service;

import com.enterprise.auth.entity.BackupCode;
import com.enterprise.auth.entity.User;
import com.enterprise.auth.repository.BackupCodeRepository;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.security.SecureRandom;
import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.List;

@Service
public class BackupCodeService {

    private static final String ALPHANUMERIC = "ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789";
    private static final SecureRandom SECURE_RANDOM = new SecureRandom();

    private final BackupCodeRepository backupCodeRepository;
    private final PasswordEncoder passwordEncoder;

    @Value("${mfa.backup.code.count:10}")
    private int backupCodeCount;

    @Value("${mfa.backup.code.length:8}")
    private int backupCodeLength;

    public BackupCodeService(BackupCodeRepository backupCodeRepository, PasswordEncoder passwordEncoder) {
        this.backupCodeRepository = backupCodeRepository;
        this.passwordEncoder = passwordEncoder;
    }

    @Transactional
    public List<String> generateBackupCodes(User user) {
        // Delete existing backup codes
        backupCodeRepository.deleteAllByUser(user);

        List<String> plainCodes = new ArrayList<>();

        for (int i = 0; i < backupCodeCount; i++) {
            String plainCode = generateRandomCode();
            plainCodes.add(plainCode);

            BackupCode backupCode = new BackupCode();
            backupCode.setCodeHash(passwordEncoder.encode(plainCode));
            backupCode.setUsed(false);
            backupCode.setUser(user);
            backupCodeRepository.save(backupCode);
        }

        return plainCodes;
    }

    @Transactional
    public boolean verifyBackupCode(User user, String code) {
        List<BackupCode> unusedCodes = backupCodeRepository.findByUserAndUsedFalse(user);

        for (BackupCode backupCode : unusedCodes) {
            if (passwordEncoder.matches(code.toUpperCase().replace("-", ""), backupCode.getCodeHash())) {
                backupCode.setUsed(true);
                backupCode.setUsedAt(LocalDateTime.now());
                backupCodeRepository.save(backupCode);
                return true;
            }
        }
        return false;
    }

    public long getRemainingBackupCodes(User user) {
        return backupCodeRepository.countUnusedByUser(user);
    }

    public long getTotalBackupCodes(User user) {
        return backupCodeRepository.findByUser(user).size();
    }

    @Transactional
    public List<String> regenerateBackupCodes(User user) {
        return generateBackupCodes(user);
    }

    @Transactional
    public void deleteBackupCodes(User user) {
        backupCodeRepository.deleteAllByUser(user);
    }

    private String generateRandomCode() {
        StringBuilder sb = new StringBuilder(backupCodeLength);
        for (int i = 0; i < backupCodeLength; i++) {
            int index = SECURE_RANDOM.nextInt(ALPHANUMERIC.length());
            sb.append(ALPHANUMERIC.charAt(index));
            // Add dash in the middle for readability
            if (i == backupCodeLength / 2 - 1) {
                sb.append('-');
            }
        }
        return sb.toString();
    }

    public String formatCodeForDisplay(String code) {
        if (code.contains("-")) return code;
        int mid = code.length() / 2;
        return code.substring(0, mid) + "-" + code.substring(mid);
    }
}

