import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.List;
import java.util.UUID;

@Service
public class AuthService {

    private static final String ISSUER = "EnterpriseAuth";

    private final UserRepository userRepository;
    private final PasswordEncoder passwordEncoder;
    private final TotpService totpService;
    private final BackupCodeService backupCodeService;
    private final AuditService auditService;

    public AuthService(UserRepository userRepository, PasswordEncoder passwordEncoder,
                       TotpService totpService, BackupCodeService backupCodeService,
                       AuditService auditService) {
        this.userRepository = userRepository;
        this.passwordEncoder = passwordEncoder;
        this.totpService = totpService;
        this.backupCodeService = backupCodeService;
        this.auditService = auditService;
    }

    @Transactional
    public User registerUser(RegisterRequest request) {
        if (userRepository.existsByUsername(request.getUsername())) {
            throw new AuthException("Username already exists", 409);
        }
        if (userRepository.existsByEmail(request.getEmail())) {
            throw new AuthException("Email already exists", 409);
        }

        User user = new User();
        user.setUsername(request.getUsername());
        user.setPassword(passwordEncoder.encode(request.getPassword()));
        user.setEmail(request.getEmail());
        user.setMfaEnabled(false);

        User savedUser = userRepository.save(user);
        auditService.log(savedUser.getId(), "USER_REGISTERED", "User registered successfully", null);
        return savedUser;
    }

    public LoginResponse login(LoginRequest request, String ipAddress) {
        User user = userRepository.findByUsername(request.getUsername())
                .orElseThrow(() -> new AuthException("Invalid username or password", 401));

        if (!passwordEncoder.matches(request.getPassword(), user.getPassword())) {
            auditService.log(user.getId(), "LOGIN_FAILED", "Invalid password attempt", ipAddress);
            throw new AuthException("Invalid username or password", 401);
        }

        LoginResponse response = new LoginResponse();

        if (user.isMfaEnabled()) {
            response.setMfaRequired(true);
            response.setMfaType("TOTP");
            response.setToken(generatePreAuthToken(user));
            auditService.log(user.getId(), "LOGIN_MFA_REQUIRED", "MFA verification required", ipAddress);
        } else {
            response.setMfaRequired(false);
            response.setToken(generateAuthToken(user));
            auditService.log(user.getId(), "LOGIN_SUCCESS", "User logged in without MFA", ipAddress);
        }

        return response;
    }

    public LoginResponse verifyMfa(MfaVerificationRequest request, String ipAddress) {
        User user = userRepository.findByUsername(request.getUsername())
                .orElseThrow(() -> new AuthException("User not found", 404));

        if (!user.isMfaEnabled()) {
            throw new AuthException("MFA is not enabled for this user", 400);
        }

        boolean valid = totpService.verifyCode(user.getMfaSecret(), request.getCode());
        if (!valid) {
            auditService.log(user.getId(), "MFA_VERIFICATION_FAILED", "Invalid TOTP code", ipAddress);
            throw new AuthException("Invalid MFA code", 401);
        }

        LoginResponse response = new LoginResponse();
        response.setMfaRequired(false);
        response.setToken(generateAuthToken(user));
        auditService.log(user.getId(), "MFA_VERIFICATION_SUCCESS", "TOTP verification successful", ipAddress);

        return response;
    }

    @Transactional
    public LoginResponse verifyBackupCode(BackupCodeVerificationRequest request, String ipAddress) {
        User user = userRepository.findByUsername(request.getUsername())
                .orElseThrow(() -> new AuthException("User not found", 404));

        if (!user.isMfaEnabled()) {
            throw new AuthException("MFA is not enabled for this user", 400);
        }

        boolean valid = backupCodeService.verifyBackupCode(user, request.getBackupCode());
        if (!valid) {
            auditService.log(user.getId(), "BACKUP_CODE_VERIFICATION_FAILED",
                    "Invalid backup code attempt", ipAddress);
            throw new AuthException("Invalid or already used backup code", 401);
        }

        long remaining = backupCodeService.getRemainingBackupCodes(user);
        auditService.log(user.getId(), "BACKUP_CODE_USED",
                String.format("Backup code used. %d remaining", remaining), ipAddress);

        LoginResponse response = new LoginResponse();
        response.setMfaRequired(false);
        response.setToken(generateAuthToken(user));

        return response;
    }

    @Transactional
    public MfaSetupResponse setupMfa(String username) {
        User user = userRepository.findByUsername(username)
                .orElseThrow(() -> new AuthException("User not found", 404));

        if (user.isMfaEnabled()) {
            throw new AuthException("MFA is already enabled", 400);
        }

        String secret = totpService.generateSecret();
        user.setMfaSecret(secret);
        userRepository.save(user);

        String qrCodeUri = totpService.generateQrCodeUri(secret, user.getUsername(), ISSUER);
        List<String> backupCodes = backupCodeService.generateBackupCodes(user);

        MfaSetupResponse response = new MfaSetupResponse();
        response.setSecret(secret);
        response.setQrCodeUri(qrCodeUri);
        response.setBackupCodes(backupCodes);

        auditService.log(user.getId(), "MFA_SETUP_INITIATED", "MFA setup initiated", null);

        return response;
    }

    @Transactional
    public void enableMfa(String username, EnableMfaRequest request, String ipAddress) {
        User user = userRepository.findByUsername(username)
                .orElseThrow(() -> new AuthException("User not found", 404));

        if (user.isMfaEnabled()) {
            throw new AuthException("MFA is already enabled", 400);
        }

        if (user.getMfaSecret() == null) {
            throw new AuthException("MFA setup not initiated. Call /mfa/setup first", 400);
        }

        boolean valid = totpService.verifyCode(user.getMfaSecret(), request.getTotpCode());
        if (!valid) {
            throw new AuthException("Invalid TOTP code. MFA not enabled.", 400);
        }

        user.setMfaEnabled(true);
        userRepository.save(user);

        auditService.log(user.getId(), "MFA_ENABLED", "MFA enabled successfully", ipAddress);
    }

    @Transactional
    public void disableMfa(String username, String password, String ipAddress) {
        User user = userRepository.findByUsername(username)
                .orElseThrow(() -> new AuthException("User not found", 404));

        if (!user.isMfaEnabled()) {
            throw new AuthException("MFA is not enabled", 400);
        }

        if (!passwordEncoder.matches(password, user.getPassword())) {
            throw new AuthException("Invalid password", 401);
        }

        user.setMfaEnabled(false);
        user.setMfaSecret(null);
        userRepository.save(user);

        backupCodeService.deleteBackupCodes(user);

        auditService.log(user.getId(), "MFA_DISABLED", "MFA disabled", ipAddress);
    }

    @Transactional
    public List<String> regenerateBackupCodes(String username, String password, String ipAddress) {
        User user = userRepository.findByUsername(username)
                .orElseThrow(() -> new AuthException("User not found", 404));

        if (!user.isMfaEnabled()) {
            throw new AuthException("MFA is not enabled", 400);
        }

        if (!passwordEncoder.matches(password, user.getPassword())) {
            throw new AuthException("Invalid password", 401);
        }

        List<String> newCodes = backupCodeService.regenerateBackupCodes(user);

        auditService.log(user.getId(), "BACKUP_CODES_REGENERATED",
                "Backup codes regenerated", ipAddress);

        return newCodes;
    }

    public BackupCodeStatusResponse getBackupCodeStatus(String username) {
        User user = userRepository.findByUsername(username)
                .orElseThrow(() -> new AuthException("User not found", 404));

        if (!user.isMfaEnabled()) {
            throw new AuthException("MFA is not enabled", 400);
        }

        long total = backupCodeService.getTotalBackupCodes(user);
        long remaining = backupCodeService.getRemainingBackupCodes(user);

        BackupCodeStatusResponse response = new BackupCodeStatusResponse();
        response.setTotalCodes(total);
        response.setUsedCodes(total - remaining);
        response.setRemainingCodes(remaining);

        return response;
    }

    private String generateAuthToken(User user) {
        // In production, use JWT with proper signing
        return "AUTH-" + UUID.randomUUID().toString() + "-" + user.getId();
    }

    private String generatePreAuthToken(User user) {
        return "PRE-AUTH-" + UUID.randomUUID().toString() + "-" + user.getId();
    }
}

