// Controller: AuthController.java
// ============================================================
package com.enterprise.auth.controller;

import com.enterprise.auth.dto.*;
import com.enterprise.auth.entity.User;
import com.enterprise.auth.service.AuthService;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.validation.Valid;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.util.HashMap;
import java.util.Map;

@RestController
@RequestMapping("/api/auth")
public class AuthController {

    private final AuthService authService;

    public AuthController(AuthService authService) {
        this.authService = authService;
    }

    @PostMapping("/register")
    public ResponseEntity<ApiResponse<Map<String, Object>>> register(
            @Valid @RequestBody RegisterRequest request) {
        User user = authService.registerUser(request);
        Map<String, Object> data = new HashMap<>();
        data.put("userId", user.getId());
        data.put("username", user.getUsername());
        data.put("email", user.getEmail());
        return ResponseEntity.status(HttpStatus.CREATED)
                .body(ApiResponse.success("User registered successfully", data));
    }

    @PostMapping("/login")
    public ResponseEntity<ApiResponse<LoginResponse>> login(
            @Valid @RequestBody LoginRequest request, HttpServletRequest httpRequest) {
        LoginResponse response = authService.login(request, getClientIp(httpRequest));
        if (response.isMfaRequired()) {
            return ResponseEntity.ok(ApiResponse.success("MFA verification required", response));
        }
        return ResponseEntity.ok(ApiResponse.success("Login successful", response));
    }

    @PostMapping("/mfa/verify")
    public ResponseEntity<ApiResponse<LoginResponse>> verifyMfa(
            @Valid @RequestBody MfaVerificationRequest request, HttpServletRequest httpRequest) {
        LoginResponse response = authService.verifyMfa(request, getClientIp(httpRequest));
        return ResponseEntity.ok(ApiResponse.success("MFA verification successful", response));
    }

    @PostMapping("/mfa/backup-code/verify")
    public ResponseEntity<ApiResponse<LoginResponse>> verifyBackupCode(
            @Valid @RequestBody BackupCodeVerificationRequest request, HttpServletRequest httpRequest) {
        LoginResponse response = authService.verifyBackupCode(request, getClientIp(httpRequest));
        return ResponseEntity.ok(ApiResponse.success("Backup code verification successful", response));
    }

    private String getClientIp(HttpServletRequest request) {
        String xForwardedFor = request.getHeader("X-Forwarded-For");
        if (xForwardedFor != null && !xForwardedFor.isEmpty()) {
            return xForwardedFor.split(",")[0].trim();
        }
        return request.getRemoteAddr();
    }
}

