// Controller: MfaController.java
// ============================================================
package com.enterprise.auth.controller;

import com.enterprise.auth.dto.*;
import com.enterprise.auth.service.AuthService;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.validation.Valid;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.util.List;
import java.util.Map;

@RestController
@RequestMapping("/api/mfa")
public class MfaController {

    private final AuthService authService;

    public MfaController(AuthService authService) {
        this.authService = authService;
    }

    @PostMapping("/setup/{username}")
    public ResponseEntity<ApiResponse<MfaSetupResponse>> setupMfa(@PathVariable String username) {
        MfaSetupResponse response = authService.setupMfa(username);
        return ResponseEntity.ok(ApiResponse.success(
                "MFA setup initiated. Scan QR code and verify with TOTP to enable. " +
                        "Save your backup codes securely!", response));
    }

    @PostMapping("/enable/{username}")
    public ResponseEntity<ApiResponse<Void>> enableMfa(
            @PathVariable String username,
            @Valid @RequestBody EnableMfaRequest request,
            HttpServletRequest httpRequest) {
        authService.enableMfa(username, request, getClientIp(httpRequest));
        return ResponseEntity.ok(ApiResponse.success("MFA enabled successfully"));
    }

    @PostMapping("/disable/{username}")
    public ResponseEntity<ApiResponse<Void>> disableMfa(
            @PathVariable String username,
            @RequestBody Map<String, String> body,
            HttpServletRequest httpRequest) {
        String password = body.get("password");
        if (password == null || password.isBlank()) {
            return ResponseEntity.badRequest()
                    .body(ApiResponse.error("Password is required to disable MFA"));
        }
        authService.disableMfa(username, password, getClientIp(httpRequest));
        return ResponseEntity.ok(ApiResponse.success("MFA disabled successfully"));
    }

    @PostMapping("/backup-codes/regenerate/{username}")
    public ResponseEntity<ApiResponse<List<String>>> regenerateBackupCodes(
            @PathVariable String username,
            @RequestBody Map<String, String> body,
            HttpServletRequest httpRequest) {
        String password = body.get("password");
        if (password == null || password.isBlank()) {
            return ResponseEntity.badRequest()
                    .body(ApiResponse.error("Password is required to regenerate backup codes"));
        }
        List<String> codes = authService.regenerateBackupCodes(username, password, getClientIp(httpRequest));
        return ResponseEntity.ok(ApiResponse.success(
                "Backup codes regenerated. Previous codes are now invalid. Save these securely!", codes));
    }

    @GetMapping("/backup-codes/status/{username}")
    public ResponseEntity<ApiResponse<BackupCodeStatusResponse>> getBackupCodeStatus(
            @PathVariable String username) {
        BackupCodeStatusResponse status = authService.getBackupCodeStatus(username);
        return ResponseEntity.ok(ApiResponse.success("Backup code status retrieved", status));
    }

    private String getClientIp(HttpServletRequest request) {
        String xForwardedFor = request.getHeader("X-Forwarded-For");
        if (xForwardedFor != null && !xForwardedFor.isEmpty()) {
            return xForwardedFor.split(",")[0].trim();
        }
        return request.getRemoteAddr();
    }
}

