package com.enterprise.auth.controller;

import com.enterprise.auth.dto.ApiResponse;
import com.enterprise.auth.entity.AuditLog;
import com.enterprise.auth.service.AuditService;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.util.List;

@RestController
@RequestMapping("/api/audit")
public class AuditController {

    private final AuditService auditService;

    public AuditController(AuditService auditService) {
        this.auditService = auditService;
    }

    @GetMapping("/logs/{userId}")
    public ResponseEntity<ApiResponse<List<AuditLog>>> getAuditLogs(@PathVariable Long userId) {
        List<AuditLog> logs = auditService.getAuditLogsForUser(userId);
        return ResponseEntity.ok(ApiResponse.success("Audit logs retrieved", logs));
    }
}

